import json
from elasticsearch import Elasticsearch, helpers

es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

def execute_script(index, script):
    try:
        response = es.search(
            index=index,
            body={
                "aggs": {
                    "script_agg": {
                        "script": {
                            "source": script,
                            "lang": "painless"
                        }
                    }
                }
            }
        )
        return response['aggregations']['script_agg']['value']
    except Exception as e:
        print(f"Error executing script: {e}")

def main():
    with open('req.json') as f:
        req = json.load(f)
    
    index = req['index']
    script = req['script']

    result = execute_script(index, script)
    print(result)

if __name__ == "__main__":
    main()